		await mgr.redoResolve();

		const restored = state.activeReviews.get("/ws/file.ts")!;
		expect(restored.hunks[0].resolved).toBe(true);
		expect(restored.hunks[0].accepted).toBe(true);
		expect(restored.hunks[1].resolved).toBe(false);
